class PoorBowler:
    def train_on_all_data(self, cricket_dataset):
        # ❌ No train/val split—overfits to specific batsmen
        model.train_on(cricket_dataset.all_matches)
        # ❌ No early stopping—trains until loss bottoms out
        for epoch in range(100):
            loss = model.forward_pass()
