# BEST PRACTICE: Structured fine-tuning with monitoring
class ProBowler:
    def train_with_validation(self, cricket_dataset, patience=3):
        # ✅ Split data: 70% training on varied conditions
        train_set, val_set = cricket_dataset.split(0.7)

        best_val_loss = float('inf')
        epochs_without_improvement = 0

        for epoch in range(100):
            # ✅ Train on diverse bowling scenarios
            train_loss = model.train_epoch(train_set)

            # ✅ Validate on unseen batsmen
            val_loss = model.evaluate(val_set)

            if val_loss < best_val_loss:
                best_val_loss = val_loss
                epochs_without_improvement = 0
                model.save_checkpoint()  # ✅ Save best version
            else:
                epochs_without_improvement += 1

            # ✅ Early stopping prevents overfitting
            if epochs_without_improvement >= patience:
                print(f'Early stopping at epoch {epoch}')
                break

        return model.load_checkpoint()

