# BEST PRACTICE: Prompt management with templates and versioning
class PromptBowler:
    PROMPT_TEMPLATES = {
        'v1': "Analyze batsman stance and suggest optimal bowling line.",
        'v2': "Given recent form and match situation, recommend ball with rationale.",
    }

    def get_recommendation(self, batsman_data, version='v2'):
        prompt = self.PROMPT_TEMPLATES[version]
        context = self.format_context(batsman_data)
        full_prompt = f"{prompt}\nContext: {context}"
        return llm.generate(full_prompt, temperature=0.7)
